import { Component, OnInit } from '@angular/core';
import { ActivatedRoute } from '@angular/router';
import { BaseClassTemplate } from 'src/app/core/class';
import { URLz } from 'src/app/core/enums';
import { FormStudentPromote } from 'src/app/core/forms';

@Component({
  selector: 'aam-student-promote-add',
  templateUrl: './student-promote-add.component.html',
  styleUrls: ['./student-promote-add.component.scss']
})
export class StudentPromoteAddComponent extends BaseClassTemplate implements OnInit {
  constructor(private route: ActivatedRoute) {
    super();
    this.param.ep = URLz.NO_SET;
  }

  ngOnInit(): void {
    this._id = this.getQuery('id');
    FormStudentPromote(this);
    if (this._id != "null" && Number(this._id) > 0) {
      this.onEdit();
    } else {
      this._fs._form.removeControl("id");
    }
  }

  onEdit() {
    this._http
      .get({ ...this.param, resource: this._id })
      .subscribe((res: any) => {
        let data = res.data.row;
        FormStudentPromote(this, data);
      });
  }
}
