import { Component, OnInit } from '@angular/core';
import { ActivatedRoute } from '@angular/router';
import { BaseClassTemplate } from 'src/app/core/class';
import { URLz } from 'src/app/core/enums';
import { FormSectionz } from 'src/app/core/forms';

@Component({
  selector: 'aam-sectionz-add',
  templateUrl: './sectionz-add.component.html',
  styleUrls: ['./sectionz-add.component.scss']
})
export class SectionzAddComponent extends BaseClassTemplate implements OnInit {
  constructor(private route: ActivatedRoute) {
    super();
    this.param.ep = URLz.NO_SET;
  }

  ngOnInit(): void {
    this._id = this.getQuery('id');
    FormSectionz(this);
    if (this._id != "null" && Number(this._id) > 0) {
      this.onEdit();
    } else {
      this._fs._form.removeControl("id");
    }
  }

  onEdit() {
    this._http
      .get({ ...this.param, resource: this._id })
      .subscribe((res: any) => {
        let data = res.data.row;
        FormSectionz(this, data);
      });
  }
}
